import React, { useState, useEffect } from 'react';
import './App.css';
import HomePage from './component/HomePage';
import AddRoomPage from './component/AddRoomPage';
import Header from './component/Header';
import AddDecoPage from './component/AddDecoPage';
import EditRoom from './component/EditRoom';
import {BrowserRouter as Router, Routes , Route} from 'react-router-dom';
import MyRooms from './component/MyRooms';
import Room from './component/Room';

function App() {
  const [rooms, setRooms] = useState([])
  const [currentRoom, setCurrentRoom] = useState("")
  const [room, setRoom] = useState({})

  let addRoom=(room)=>{
    let r=rooms
    r.push(room)
    setRooms(r)
  }
  useEffect(() => {
    console.log(rooms)


  }, [rooms])

  let showRooms=()=>{
    console.log(rooms)
    if(rooms!=[])
    rooms.map((i) => { return <h1>{rooms[i]}</h1> })}

  return (
      <div className="App">
        <Header />
      <Router>
        <Routes>
          <Route path={'/'} element={<HomePage/>} />
          <Route path={'/addroom'} element={<AddRoomPage addRoom={addRoom}/>} />
          <Route path={'/roomDeco'} element={<AddDecoPage />} /> 
          <Route path={'/myrooms'} element={<MyRooms  showRooms={showRooms} />} /> 
          <Route path={'/'+currentRoom.name} element={<EditRoom room={room} />} />
        </Routes>
      </Router>
    </div>)}
export default App;
